   237→    async function loadApplications() {
   238→      try {
   239→        const data = await apiCall('/candidate/applications');
   240→        if (data.success) {
   241→          applications = data.applications;
   242→          document.getElementById('applied-count').textContent = data.applications.length;
   243→        }
   244→      } catch (err) {
   245→        console.error('Load applications error:', err);
   246→      }
   247→    }
   248→
   249→    function switchTab(tab) {
   250→      currentTab = tab;
   251→
   252→      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
   253→      document.querySelector(`[data-tab="${tab}"]`).classList.add('active');
   254→
   255→      // Show/hide filters
   256→      document.getElementById('job-filters').style.display =
   257→        (tab === 'recommended' || tab === 'all') ? 'flex' : 'none';
   258→
   259→      // Close detail panel
   260→      document.getElementById('job-detail-panel').classList.remove('active');
   261→
   262→      // Render appropriate list
   263→      if (tab === 'recommended') {
   264→        renderJobs(allJobs);
   265→      } else if (tab === 'all') {
   266→        // For all, we show the same but without match info prominently
   267→        renderJobs(allJobs, false);
   268→      } else if (tab === 'saved') {
   269→        renderSavedJobs();
   270→      } else if (tab === 'applications') {
   271→        renderApplications();
   272→      }
   273→    }
   274→
   275→    function applyFilters() {
   276→      const location = document.getElementById('filter-location').value.toLowerCase();
   277→      const type = document.getElementById('filter-type').value;
   278→      const minMatch = parseInt(document.getElementById('filter-match').value) || 0;
   279→
   280→      let filtered = allJobs.filter(job => {
   281→        if (location && job.location && !job.location.toLowerCase().includes(location)) return false;
   282→        if (type && job.job_type !== type) return false;
   283→        if (minMatch && (!job.match || job.match.match_score < minMatch)) return false;
   284→        return true;
   285→      });
   286→
   287→      renderJobs(filtered);
   288→    }
   289→
   290→    function renderJobs(jobs, showMatch = true) {
   291→      const container = document.getElementById('jobs-container');
   292→
   293→      if (!jobs || jobs.length === 0) {
   294→        container.innerHTML = `
   295→          <div class="empty-state">
   296→            <p>No jobs found matching your criteria.</p>
   297→          </div>
   298→        `;
   299→        return;
   300→      }
   301→
   302→      container.innerHTML = `
   303→        <div class="jobs-list">
   304→          ${jobs.map(job => renderJobCard(job, showMatch)).join('')}
   305→        </div>
   306→      `;
   307→    }
   308→
   309→    function renderJobCard(job, showMatch = true) {
   310→      const match = job.match || {};
   311→      const matchScore = match.match_score || 50;
   312→      const matchLevel = match.match_level || 'fair';
   313→      const isSaved = savedJobs.some(s => s.id === job.id);
   314→      const hasApplied = applications.some(a => a.job_id === job.id);
   315→
   316→      return `
   317→        <div class="job-card ${hasApplied ? 'applied' : ''}" onclick="showJobDetail(${job.id})">
   318→          <div class="job-card-main">
   319→            <div class="job-card-header">
   320→              <h3>${job.title}</h3>
   321→              <button class="save-btn ${isSaved ? 'saved' : ''}" onclick="event.stopPropagation(); toggleSave(${job.id})">
   322→                ${isSaved ? '❤️' : '🤍'}
   323→              </button>
   324→            </div>
   325→            <p class="job-company">${job.company || job.posted_by_company || 'Company'}</p>
   326→            <div class="job-meta">
   327→              ${job.location ? `<span class="job-location">📍 ${job.location}</span>` : ''}
   328→              ${job.job_type ? `<span class="job-type">${job.job_type}</span>` : ''}
   329→              ${job.salary_range ? `<span class="job-salary">💰 ${job.salary_range}</span>` : ''}
   330→            </div>
   331→          </div>
   332→          ${showMatch ? `
   333→            <div class="job-card-match">
   334→              <div class="match-indicator ${matchLevel}">
