   206→    document.addEventListener('DOMContentLoaded', async () => {
   207→      const user = await checkAuth();
   208→      if (!user) {
   209→        window.location.href = '/login.html';
   210→        return;
   211→      }
   212→      // Verify recruiter/employer role - must have company_id and appropriate role
   213→      const allowedRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   214→      if (!user.company_id || !allowedRoles.includes(user.role)) {
   215→        window.location.href = '/candidate-dashboard.html';
   216→        return;
   217→      }
   218→
   219→      const name = user.name || user.email.split('@')[0];
   220→      document.getElementById('user-name').textContent = name;
   221→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   222→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   223→      document.getElementById('dropdown-user-name').textContent = name;
   224→      document.getElementById('dropdown-user-email').textContent = user.email;
   225→
   226→      // Setup user menu dropdown
   227→      const userMenuToggle = document.getElementById('user-menu-toggle');
   228→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   229→      if (userMenuToggle && userDropdownMenu) {
   230→        userMenuToggle.addEventListener('click', (e) => {
   231→          e.stopPropagation();
   232→          userDropdownMenu.classList.toggle('active');
   233→        });
   234→        document.addEventListener('click', () => {
   235→          userDropdownMenu.classList.remove('active');
   236→        });
   237→      }
   238→
   239→      // Setup filter tabs
   240→      document.querySelectorAll('.filter-tab').forEach(tab => {
   241→        tab.addEventListener('click', () => {
   242→          document.querySelectorAll('.filter-tab').forEach(t => t.classList.remove('active'));
   243→          tab.classList.add('active');
   244→          currentFilter = tab.dataset.status;
   245→          renderApplications();
   246→        });
   247→      });
   248→
   249→      // Setup job filter
   250→      document.getElementById('job-filter').addEventListener('change', (e) => {
   251→        currentJob = e.target.value;
   252→        renderApplications();
   253→      });
   254→
   255→      loadJobs();
   256→      loadApplications();
   257→    });
   258→
   259→    async function loadJobs() {
   260→      try {
   261→        const data = await apiCall('/recruiter/jobs');
   262→        if (data.jobs) {
   263→          const select = document.getElementById('job-filter');
   264→          data.jobs.forEach(job => {
   265→            const option = document.createElement('option');
   266→            option.value = job.id;
   267→            option.textContent = job.title;
   268→            select.appendChild(option);
   269→          });
   270→        }
   271→      } catch (err) {
   272→        console.error('Failed to load jobs:', err);
   273→      }
   274→    }
   275→
   276→    async function loadApplications() {
   277→      try {
   278→        const data = await apiCall('/recruiter/applications');
   279→        if (data.applications) {
   280→          applications = data.applications;
   281→          updateStats(applications);
   282→          renderApplications();
   283→        }
   284→      } catch (err) {
   285→        console.error('Failed to load applications:', err);
   286→        document.getElementById('applications-list').innerHTML = `
   287→          <div class="empty-state">
   288→            <p>Failed to load applications</p>
   289→          </div>
   290→        `;
   291→      }
   292→    }
   293→
   294→    function updateStats(apps) {
   295→      document.getElementById('total-applications').textContent = apps.length;
   296→
   297→      const today = new Date().toDateString();
   298→      const newToday = apps.filter(a => new Date(a.applied_at).toDateString() === today).length;
   299→      document.getElementById('new-applications').textContent = newToday;
   300→
   301→      document.getElementById('reviewing-count').textContent =
   302→        apps.filter(a => a.status === 'reviewing').length;
   303→      document.getElementById('offered-count').textContent =
   304→        apps.filter(a => a.status === 'offered').length;
   305→    }
   306→
   307→    function renderApplications() {
   308→      const container = document.getElementById('applications-list');
   309→
   310→      let filtered = applications;
   311→      if (currentFilter !== 'all') {
   312→        filtered = filtered.filter(a => a.status === currentFilter);
   313→      }
   314→      if (currentJob) {
   315→        filtered = filtered.filter(a => a.job_id == currentJob);
   316→      }
   317→
   318→      if (filtered.length === 0) {
   319→        container.innerHTML = `
   320→          <div class="empty-state">
   321→            <p>No applications found</p>
   322→            <a href="/job-create.html" class="btn btn-primary btn-sm">Post a Job</a>
   323→          </div>
   324→        `;
   325→        return;
   326→      }
   327→
   328→      container.innerHTML = filtered.map(app => `
   329→        <div class="application-card">
   330→          <div class="application-header">
   331→            <div class="candidate-info">
   332→              <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
   333→              <div class="candidate-details">
   334→                <h3>${app.candidate_name || 'Unknown'}</h3>
   335→                <p>${app.job_title || 'Position'}</p>
   336→              </div>
   337→            </div>
   338→            <div class="application-meta">
   339→              ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OmniScore</span>` : ''}
   340→              <span class="status-badge ${app.status}">${app.status}</span>
   341→            </div>
   342→          </div>
   343→          <div class="application-body">
   344→            <div class="application-info">
   345→              <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
   346→              <span class="info-item">📅 Applied ${formatDate(app.applied_at)}</span>
   347→            </div>
   348→            ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
   349→          </div>
   350→          <div class="application-actions">
   351→            <button onclick="updateStatus(${app.id}, 'reviewing')" class="btn btn-ghost btn-sm" ${app.status !== 'applied' ? 'disabled' : ''}>
   352→              Review
   353→            </button>
   354→            <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">
   355→              Schedule Interview
   356→            </button>
   357→            <button onclick="makeOffer(${app.id}, ${app.candidate_id}, '${(app.candidate_name || '').replace(/'/g, "\\'")}', '${(app.candidate_email || '').replace(/'/g, "\\'")}', ${app.job_id}, '${(app.job_title || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm" ${app.status === 'offered' || app.status === 'hired' ? 'disabled' : ''}>
   358→              Make Offer
   359→            </button>
   360→            <button onclick="updateStatus(${app.id}, 'rejected')" class="btn btn-ghost btn-sm danger">
   361→              Reject
   362→            </button>
   363→          </div>
   364→        </div>
   365→      `).join('');
   366→    }
