   379→    async function updateStatus(appId, status) {
   380→      try {
   381→        const result = await apiCall(`/recruiter/applications/${appId}/status`, {
   382→          method: 'PUT',
   383→          body: JSON.stringify({ status })
   384→        });
   385→        if (result.success) {
   386→          loadApplications();
   387→        }
   388→      } catch (err) {
   389→        alert('Failed to update status');
   390→      }
   391→    }
