   334→    function renderInterviews() {
   335→      const container = document.getElementById('interviews-list');
   336→      const now = new Date();
   337→      const today = now.toDateString();
   338→
   339→      let filtered = interviews;
   340→      if (currentFilter === 'upcoming') {
   341→        filtered = filtered.filter(i => new Date(i.scheduled_at) > now && i.status !== 'completed');
   342→      } else if (currentFilter === 'today') {
   343→        filtered = filtered.filter(i => new Date(i.scheduled_at).toDateString() === today);
   344→      } else if (currentFilter === 'completed') {
   345→        filtered = filtered.filter(i => i.status === 'completed');
   346→      }
   347→
   348→      if (filtered.length === 0) {
   349→        container.innerHTML = `
   350→          <div class="empty-state">
   351→            <p>No interviews ${currentFilter === 'all' ? '' : currentFilter}</p>
   352→            <button onclick="showScheduleModal()" class="btn btn-primary btn-sm">Schedule an Interview</button>
