   377→              </div>
   378→            </div>
   379→            <div class="interview-meta">
   380→              <span class="interview-type-badge ${interview.interview_type}">${interview.interview_type || 'Interview'}</span>
   381→              <span class="interview-duration">${interview.duration || 60} min</span>
   382→            </div>
   383→            <div class="interview-actions">
   384→              ${!isPast ? `
   385→                <button onclick="joinInterview('${interview.id}')" class="btn btn-primary btn-sm">
   386→                  ${interview.interview_type === 'video' ? '🎥 Join Video' : '📞 Join'}
   387→                </button>
   388→                ${interview.meeting_link ? `<button onclick="copyMeetingLink('${interview.meeting_link}')" class="btn btn-ghost btn-sm" title="Copy link">📋</button>` : ''}
   389→                <button onclick="reschedule('${interview.id}')" class="btn btn-ghost btn-sm">Reschedule</button>
   390→              ` : `
   391→                <button onclick="markCompleted('${interview.id}')" class="btn btn-ghost btn-sm">Mark Complete</button>
   392→              `}
   393→              <button onclick="cancelInterview('${interview.id}')" class="btn btn-ghost btn-sm danger">Cancel</button>
   394→            </div>
   395→          </div>
