   412→    async function scheduleInterview(e) {
   413→      e.preventDefault();
   414→      const applicationId = document.getElementById('candidate-select').value;
   415→      const type = document.getElementById('interview-type').value;
   416→      const date = document.getElementById('interview-date').value;
   417→      const time = document.getElementById('interview-time').value;
   418→      const duration = document.getElementById('interview-duration').value;
   419→      const notes = document.getElementById('interview-notes').value;
   420→
   421→      const scheduledAt = new Date(`${date}T${time}`);
   422→
   423→      try {
   424→        const result = await apiCall('/recruiter/interviews', {
   425→          method: 'POST',
   426→          body: JSON.stringify({
   427→            application_id: applicationId,
   428→            interview_type: type,
   429→            scheduled_at: scheduledAt.toISOString(),
   430→            duration: parseInt(duration),
   431→            notes
   432→          })
   433→        });
   434→
   435→        if (result.success) {
   436→          closeScheduleModal();
   437→          loadInterviews();
   438→        } else {
   439→          alert(result.error || 'Failed to schedule interview');
   440→        }
