   446→    function joinInterview(id) {
   447→      // Find the interview to get meeting link
   448→      const interview = interviews.find(i => i.id == id);
   449→      if (!interview) {
   450→        alert('Interview not found');
   451→        return;
   452→      }
   453→
   454→      // If meeting link exists, open it
   455→      if (interview.meeting_link) {
   456→        window.open(interview.meeting_link, '_blank');
   457→        return;
   458→      }
   459→
   460→      // Generate a Jitsi Meet room based on interview ID
   461→      const roomName = `HireLoop-Interview-${id}-${Date.now().toString(36)}`;
   462→      const meetingLink = `https://meet.jit.si/${roomName}`;
   463→
   464→      // Update the interview with the meeting link
   465→      updateMeetingLink(id, meetingLink).then(() => {
   466→        window.open(meetingLink, '_blank');
   467→      });
   468→    }
