   487→    async function markCompleted(id) {
   488→      try {
   489→        const result = await apiCall(`/recruiter/interviews/${id}`, {
   490→          method: 'PUT',
   491→          body: JSON.stringify({ status: 'completed' })
   492→        });
   493→        if (result.success) {
   494→          loadInterviews();
   495→        }
   496→      } catch (err) {
   497→        alert('Failed to update interview');
