   501→    async function cancelInterview(id) {
   502→      if (!confirm('Cancel this interview?')) return;
   503→      try {
   504→        const result = await apiCall(`/recruiter/interviews/${id}`, {
   505→          method: 'DELETE'
   506→        });
   507→        if (result.success) {
   508→          loadInterviews();
   509→        }
   510→      } catch (err) {
