   773→    // Microphone status helpers
   774→    function updateMicStatus(status, label) {
   775→      const micStatusEl = document.getElementById('mic-status');
   776→      const micLabelEl = document.getElementById('mic-label');
   777→
   778→      micStatusEl.className = 'mic-status ' + status;
