   873→    function startRecording() {
   874→      recordedChunks = [];
   875→
   876→      try {
   877→        // Use mimeType with both video AND audio codecs
   878→        let mimeType = 'video/webm;codecs=vp9,opus';
   879→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   880→          mimeType = 'video/webm;codecs=vp8,opus';
   881→        }
   882→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   883→          mimeType = 'video/webm';
   884→        }
   885→        console.log('Recording with mimeType:', mimeType);
   886→
   887→        // Verify audio tracks before recording
   888→        const audioTracks = mediaStream.getAudioTracks();
   889→        if (audioTracks.length === 0 || !audioTracks[0].enabled) {
   890→          alert('Microphone is not active. Please check your mic permissions and try again.');
   891→          return;
   892→        }
   893→
   894→        mediaRecorder = new MediaRecorder(mediaStream, { mimeType });
   895→
   896→        mediaRecorder.ondataavailable = (event) => {
   897→          if (event.data.size > 0) {
   898→            recordedChunks.push(event.data);
   899→          }
   900→        };
   901→
   902→        mediaRecorder.onstop = handleRecordingStop;
   903→
   904→        mediaRecorder.start();
   905→
   906→        // Start video analysis
   907→        if (videoAnalyzer) {
   908→          videoAnalyzer.reset();
   909→          videoAnalyzer.startAnalysis(document.getElementById('recording-video'), 500);
   910→          document.getElementById('analysis-toggle').style.display = 'block';
   911→        }
   912→
   913→        // Update UI
   914→        document.getElementById('record-btn').style.display = 'none';
   915→        document.getElementById('stop-btn').style.display = 'inline-flex';
   916→        document.getElementById('recording-indicator').classList.add('active');
   917→
   918→        // Start timer
   919→        timerInterval = setInterval(() => {
   920→          timeRemaining--;
   921→          updateTimer();
   922→
   923→          if (timeRemaining <= 0) {
   924→            stopRecording();
   925→          }
   926→        }, 1000);
   927→      } catch (err) {
   928→        console.error('Recording error:', err);
   929→        alert('Failed to start recording. Please try again.');
   930→      }
   931→    }
