   933→    function stopRecording() {
   934→      if (mediaRecorder && mediaRecorder.state !== 'inactive') {
   935→        mediaRecorder.stop();
   936→        clearInterval(timerInterval);
   937→
   938→        // Stop video analysis and save data
   939→        if (videoAnalyzer) {
   940→          videoAnalyzer.stopAnalysis();
   941→          const analysis = videoAnalyzer.getFinalAnalysis();
   942→
   943→          if (analysis) {
