   960→      const blob = new Blob(recordedChunks, { type: 'video/webm' });
   961→      const videoUrl = URL.createObjectURL(blob);
   962→
   963→      // Show review state
   964→      document.getElementById('review-question-number').textContent =
   965→        `Question ${currentQuestionIndex + 1} of ${questions.length}`;
   966→      document.getElementById('review-question-text').textContent = questions[currentQuestionIndex].question;
   967→
   968→      const playbackVideo = document.getElementById('playback-video');
   969→      playbackVideo.src = videoUrl;
   970→
   971→      // Update retake button
   972→      const retakeBtn = document.getElementById('retake-btn');
   973→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   974→      if (retakesForQuestion >= 1) {
   975→        retakeBtn.disabled = true;
   976→        retakeBtn.textContent = '🔄 No retakes remaining';
   977→      } else {
   978→        retakeBtn.disabled = false;
   979→        retakeBtn.textContent = `🔄 Retake (${1 - retakesForQuestion} remaining)`;
   980→      }
   981→
   982→      showState('review');
   983→
   984→      // Store the blob temporarily
   985→      window.currentRecordingBlob = blob;
   986→    }
