  1000→    async function acceptResponse() {
  1001→      // Show loading
  1002→      document.getElementById('submit-btn').disabled = true;
  1003→      document.getElementById('submit-btn').innerHTML = '<span class="loading-spinner"></span> Uploading...';
  1004→
  1005→      try {
  1006→        // Upload video
  1007→        const videoUrl = await uploadVideo(window.currentRecordingBlob, currentQuestionIndex);
