   269→        });
   270→
   271→        if (!response.ok) throw new Error('Failed to start assessment');
   272→
   273→        const data = await response.json();
   274→        sessionId = data.sessionId;
   275→        currentQuestion = data.question;
   276→        
   277→        displayQuestion();
   278→        startTimer(currentQuestion.timeLimit);
