   329→
   330→    // Submit answer
   331→    async function submitAnswer() {
   332→      // Get answer
   333→      if (currentQuestion.type === 'multiple_choice') {
   334→        if (!selectedAnswer) {
   335→          alert('Please select an answer');
   336→          return;
   337→        }
   338→      } else {
