   341→        if (!selectedAnswer) {
   342→          alert('Please provide an answer');
   343→          return;
   344→        }
   345→      }
   346→
   347→      // Calculate time taken
   348→      const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000);
   349→
   350→      // Stop timer
