   484→          },
   485→          body: JSON.stringify({
   486→            sessionId,
   487→            eventType,
   488→            eventData
   489→          })
   490→        });
   491→      } catch (error) {
   492→        console.error('Failed to log event:', error);
   493→      }
   494→    }
   495→
   496→    // Prevent right-click (basic anti-cheat)
