  1272→    // ====== Signature Canvas ======
  1273→    function initSignatureCanvas() {
  1274→      const canvas = document.getElementById('signatureCanvas');
  1275→      if (!canvas) return;
  1276→
  1277→      signatureCanvas = canvas;
  1278→      signatureCtx = canvas.getContext('2d');
  1279→
  1280→      // Set canvas size
  1281→      const rect = canvas.parentElement.getBoundingClientRect();
  1282→      canvas.width = rect.width - 48;
  1283→      canvas.height = 150;
  1284→
  1285→      signatureCtx.strokeStyle = '#1a1a2e';
  1286→      signatureCtx.lineWidth = 2;
  1287→      signatureCtx.lineCap = 'round';
  1288→      signatureCtx.lineJoin = 'round';
  1289→
  1290→      canvas.addEventListener('mousedown', startDrawing);
  1291→      canvas.addEventListener('mousemove', draw);
  1292→      canvas.addEventListener('mouseup', stopDrawing);
  1293→      canvas.addEventListener('mouseleave', stopDrawing);
  1294→
  1295→      // Touch support
  1296→      canvas.addEventListener('touchstart', (e) => {
  1297→        e.preventDefault();
  1298→        const touch = e.touches[0];
  1299→        const rect = canvas.getBoundingClientRect();
  1300→        startDrawing({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1301→      });
  1302→      canvas.addEventListener('touchmove', (e) => {
  1303→        e.preventDefault();
  1304→        const touch = e.touches[0];
  1305→        const rect = canvas.getBoundingClientRect();
  1306→        draw({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1307→      });
  1308→      canvas.addEventListener('touchend', stopDrawing);
  1309→    }
  1310→
  1311→    function startDrawing(e) {
  1312→      isDrawing = true;
  1313→      signatureCtx.beginPath();
  1314→      signatureCtx.moveTo(e.offsetX, e.offsetY);
  1315→    }
  1316→
  1317→    function draw(e) {
  1318→      if (!isDrawing) return;
  1319→      signatureCtx.lineTo(e.offsetX, e.offsetY);
  1320→      signatureCtx.stroke();
  1321→      hasSigned = true;
  1322→      const btn = document.getElementById('signAllBtn');
  1323→      if (btn) btn.disabled = false;
  1324→    }
  1325→
  1326→    function stopDrawing() {
  1327→      isDrawing = false;
  1328→    }
  1329→
  1330→    function clearSignature() {
  1331→      if (!signatureCanvas || !signatureCtx) return;
  1332→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1333→      hasSigned = false;
  1334→      const btn = document.getElementById('signAllBtn');
  1335→      if (btn) btn.disabled = true;
  1336→    }
  1337→
  1338→    function typeSignature() {
  1339→      const name = prompt('Type your full legal name as your signature:');
  1340→      if (!name || !name.trim()) return;
  1341→
  1342→      if (!signatureCanvas || !signatureCtx) return;
  1343→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1344→      signatureCtx.font = 'italic 32px "Times New Roman", serif';
  1345→      signatureCtx.fillStyle = '#1a1a2e';
  1346→      signatureCtx.textAlign = 'center';
  1347→      signatureCtx.fillText(name.trim(), signatureCanvas.width / 2, 90);
  1348→      hasSigned = true;
  1349→      const btn = document.getElementById('signAllBtn');
  1350→      if (btn) btn.disabled = false;
  1351→    }
  1352→
  1353→    // ====== Navigation & Save ======
  1354→    function goToStep(step) {
  1355→      currentStep = step;
  1356→      renderStep();
  1357→      window.scrollTo({ top: 0, behavior: 'smooth' });
  1358→    }
  1359→
  1360→    async function saveWizardStep(step, data) {
  1361→      showSaving();
  1362→      try {
  1363→        const res = await fetch('/api/onboarding/wizard/save-step', {
  1364→          method: 'POST',
  1365→          headers: getAuthHeaders(),
  1366→          body: JSON.stringify({
  1367→            checklist_id: checklistData.id,
  1368→            step: step,
  1369→            data: data
  1370→          })
  1371→        });
  1372→
  1373→        if (!res.ok) throw new Error('Failed to save');
  1374→
  1375→        const result = await res.json();
  1376→        wizardState = result.wizard;
  1377→
  1378→        hideSaving();
  1379→
  1380→        // If step 3 just completed, generate documents
  1381→        if (step === 3) {
  1382→          await generateDocuments();
  1383→        }
  1384→
  1385→        currentStep = step + 1;
  1386→        renderStep();
  1387→        window.scrollTo({ top: 0, behavior: 'smooth' });
  1388→      } catch (err) {
  1389→        hideSaving();
  1390→        console.error('Error saving step:', err);
  1391→        alert('Failed to save. Please try again.');
  1392→      }
  1393→    }
  1394→
  1395→    async function generateDocuments() {
  1396→      try {
  1397→        const res = await fetch('/api/onboarding/wizard/generate-documents', {
  1398→          method: 'POST',
  1399→          headers: getAuthHeaders(),
  1400→          body: JSON.stringify({ checklist_id: checklistData.id })
  1401→        });
  1402→
  1403→        if (!res.ok) throw new Error('Failed to generate');
  1404→
  1405→        const result = await res.json();
  1406→        documentsData = result.documents;
  1407→      } catch (err) {
  1408→        console.error('Error generating documents:', err);
  1409→      }
  1410→    }
  1411→
  1412→    async function retryGenerateDocuments() {
  1413→      const btn = document.getElementById('retryGenBtn');
  1414→      const msg = document.getElementById('docGenMsg');
  1415→      const spinner = document.getElementById('docSpinner');
  1416→      if (btn) btn.style.display = 'none';
  1417→      if (spinner) spinner.style.display = 'block';
  1418→      if (msg) { msg.textContent = 'Retrying document generation...'; msg.style.color = 'var(--text-muted)'; }
  1419→
  1420→      await generateDocuments();
  1421→      if (documentsData && documentsData.length > 0) {
  1422→        renderStep();
  1423→      } else {
  1424→        if (spinner) spinner.style.display = 'none';
  1425→        if (msg) { msg.textContent = 'Still unable to generate. Please try again.'; msg.style.color = '#ef4444'; }
  1426→        if (btn) btn.style.display = 'inline-block';
  1427→      }
  1428→    }
  1429→
  1430→    async function signAllDocuments() {
  1431→      if (!hasSigned) {
  1432→        alert('Please draw or type your signature first.');
  1433→        return;
  1434→      }
  1435→
  1436→      const signatureDataUrl = signatureCanvas ? signatureCanvas.toDataURL('image/png') : 'typed_signature';
  1437→
  1438→      showSaving();
  1439→      try {
  1440→        const res = await fetch('/api/onboarding/wizard/sign-all', {
  1441→          method: 'POST',
  1442→          headers: getAuthHeaders(),
  1443→          body: JSON.stringify({
  1444→            checklist_id: checklistData.id,
  1445→            signature_data: signatureDataUrl
  1446→          })
  1447→        });
  1448→
  1449→        if (!res.ok) throw new Error('Failed to sign');
  1450→
  1451→        const result = await res.json();
  1452→        documentsData = result.signed_documents;
  1453→
  1454→        hideSaving();
  1455→
  1456→        // Move to completion
  1457→        currentStep = 5;
  1458→        if (wizardState) wizardState.wizard_status = 'completed';
  1459→        renderStep();
  1460→        window.scrollTo({ top: 0, behavior: 'smooth' });
  1461→      } catch (err) {
  1462→        hideSaving();
  1463→        console.error('Error signing:', err);
  1464→        alert('Failed to sign documents. Please try again.');
  1465→      }
  1466→    }
  1467→
  1468→    function completeOnboarding() {
  1469→      currentStep = 5;
  1470→      renderStep();
  1471→    }
  1472→
  1473→    function showSaving() {
  1474→      document.getElementById('savingIndicator').style.display = 'block';
  1475→    }
  1476→
  1477→    function hideSaving() {
  1478→      document.getElementById('savingIndicator').style.display = 'none';
  1479→    }
  1480→
  1481→    function escapeHtml(text) {
  1482→      if (!text) return '';
  1483→      const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' };
  1484→      return String(text).replace(/[&<>"']/g, m => map[m]);
  1485→    }
