   451→  <script src="/js/auth.js"></script>
   452→  <script>
   453→    const BACKEND_URL = '/api';
   454→    let currentCandidateId = null;
   455→
   456→    async function loadOnboardingDocuments() {
   457→      try {
   458→        const response = await fetch(`${BACKEND_URL}/onboarding/recruiter/summary`, {
   459→          headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   460→        });
   461→
   462→        if (!response.ok) throw new Error('Failed to load documents');
   463→
   464→        const data = await response.json();
   465→        displayCandidates(data);
   466→      } catch (error) {
   467→        console.error('Error:', error);
   468→        document.getElementById('empty-state').style.display = 'block';
   469→        document.getElementById('candidates-container').innerHTML = '';
   470→      }
   471→    }
   472→
   473→    function displayCandidates(candidates) {
   474→      const container = document.getElementById('candidates-container');
   475→
   476→      if (!candidates || candidates.length === 0) {
   477→        document.getElementById('empty-state').style.display = 'block';
   478→        container.innerHTML = '';
   479→        return;
   480→      }
   481→
   482→      document.getElementById('empty-state').style.display = 'none';
   483→
   484→      container.innerHTML = candidates.map(candidate => {
   485→        const total = parseInt(candidate.total_documents) || 0;
   486→        const signed = parseInt(candidate.signed_documents) || 0;
   487→        const pct = total > 0 ? Math.round((signed / total) * 100) : 0;
   488→        const barColor = pct === 100 ? '#10b981' : pct > 0 ? '#f59e0b' : '#e5e7eb';
   489→
   490→        return `
   491→        <div class="candidate-card" onclick="viewCandidateDetails(${candidate.candidate_id})">
   492→          <div class="candidate-header">
   493→            <div class="candidate-info">
   494→              <h3>${escapeHtml(candidate.candidate_name)}</h3>
   495→              <div class="candidate-email">${escapeHtml(candidate.candidate_email)}</div>
   496→              ${candidate.job_title ? `<div class="candidate-job">${escapeHtml(candidate.job_title)}</div>` : ''}
   497→            </div>
   498→            <span class="onboarding-status status-${candidate.onboarding_status || 'pending'}">
   499→              ${formatStatus(candidate.onboarding_status)}
   500→            </span>
   501→          </div>
   502→
   503→          <!-- Progress bar -->
   504→          <div style="margin-top: 12px;">
   505→            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px;">
   506→              <span style="font-size: 12px; color: var(--text-muted);">Document Progress</span>
   507→              <span style="font-size: 12px; font-weight: 600; color: ${barColor};">${pct}%</span>
   508→            </div>
   509→            <div style="height: 6px; background: var(--border-color); border-radius: 3px; overflow: hidden;">
   510→              <div style="height: 100%; width: ${pct}%; background: ${barColor}; border-radius: 3px; transition: width 0.3s;"></div>
   511→            </div>
   512→          </div>
   513→
   514→          <div class="docs-summary">
   515→            <div class="summary-item">
   516→              <strong>${signed}</strong>
   517→              <span>Signed</span>
   518→            </div>
   519→            <div class="summary-item">
   520→              <strong>${total}</strong>
   521→              <span>Total Docs</span>
   522→            </div>
   523→          </div>
   524→
   525→          ${candidate.due_date ? `
   526→            <div style="margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--border-color); font-size: 12px; color: var(--text-muted);">
   527→              Due: ${formatDate(candidate.due_date)}
   528→            </div>
   529→          ` : ''}
   530→
   531→          <div style="margin-top: 12px; text-align: right;">
   532→            <a class="view-link" onclick="event.stopPropagation(); viewCandidateDetails(${candidate.candidate_id})">View Details →</a>
   533→          </div>
   534→        </div>
   535→      `}).join('');
   536→    }
   537→
   538→    async function viewCandidateDetails(candidateId) {
   539→      currentCandidateId = candidateId;
   540→
   541→      try {
   542→        // Load candidate details and documents
   543→        const response = await fetch(
   544→          `${BACKEND_URL}/onboarding/recruiter/candidate/${candidateId}/documents`,
   545→          { headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` } }
   546→        );
   547→
   548→        if (!response.ok) throw new Error('Failed to load documents');
   549→
   550→        const documents = await response.json();
   551→        const candidateData = documents[0];
   552→
   553→        // Update modal header
   554→        document.getElementById('modal-candidate-name').textContent = candidateData.candidate_name;
   555→        document.getElementById('modal-candidate-email').textContent = candidateData.candidate_email;
   556→
   557→        // Update details
   558→        document.getElementById('modal-job').textContent = candidateData.job_title || '—';
   559→        document.getElementById('modal-start-date').textContent = candidateData.start_date ? formatDate(candidateData.start_date) : '—';
   560→
   561→        // Display documents
   562→        const docsContainer = document.getElementById('modal-documents');
   563→        if (documents.length === 0) {
   564→          docsContainer.innerHTML = '<p style="color: var(--text-muted);">No documents yet</p>';
   565→        } else {
   566→          docsContainer.innerHTML = documents.map(doc => `
   567→            <div class="doc-item" style="border-left-color: ${doc.signed_at ? '#10b981' : doc.uploaded_at ? '#3b82f6' : '#e5e7eb'};">
   568→              <div class="doc-item-header">
   569→                <span class="doc-item-type">${escapeHtml(doc.document_type)}</span>
   570→                <span class="doc-item-date">${formatDate(doc.created_at)}</span>
   571→              </div>
   572→              <div style="display: flex; align-items: center; justify-content: space-between; margin-top: 8px;">
   573→                <div>
   574→                  ${doc.signed_at ? `
   575→                    <span class="document-status status-signed">✓ Signed ${formatDate(doc.signed_at)}</span>
   576→                  ` : doc.uploaded_at ? `
   577→                    <span class="document-status status-uploaded">✓ Generated</span>
   578→                  ` : `
   579→                    <span class="document-status status-pending-doc">Pending</span>
   580→                  `}
   581→                </div>
   582→                <div style="display: flex; gap: 8px;">
   583→                  ${doc.document_content ? `<a class="view-link" onclick="viewDocContent(${doc.id}, '${escapeHtml(doc.document_type)}')">View Details</a>` : ''}
   584→                  ${doc.document_content ? `<a class="view-link" href="/api/onboarding/recruiter/document/${doc.id}/download" target="_blank" style="color: #10b981;">⬇ Download</a>` : ''}
   585→                  ${doc.document_url ? `<a href="${doc.document_url}" target="_blank" class="view-link">Open File</a>` : ''}
   586→                </div>
   587→              </div>
   588→              ${doc.content_summary ? `<p style="font-size: 12px; color: var(--text-muted); margin-top: 8px;">${escapeHtml(doc.content_summary)}</p>` : ''}
   589→              ${doc.signer_ip ? `<p style="font-size: 11px; color: var(--text-muted); margin-top: 4px;">Audit: IP ${escapeHtml(doc.signer_ip)} | ${formatDate(doc.signed_at)}</p>` : ''}
   590→            </div>
   591→          `).join('');
   592→
   593→          // Store docs for preview
   594→          window._currentDocs = documents;
   595→
   596→          // Show download all button if docs have content
   597→          const hasContent = documents.some(d => d.document_content);
   598→          const dlBtn = document.getElementById('download-all-btn');
   599→          if (dlBtn) dlBtn.style.display = hasContent ? 'inline-block' : 'none';
   600→        }
   601→
   602→        // Show modal
   603→        document.getElementById('modal').classList.add('active');
   604→      } catch (error) {
   605→        console.error('Error:', error);
   606→        alert('Failed to load candidate details');
   607→      }
   608→    }
   609→
   610→    function closeModal() {
   611→      document.getElementById('modal').classList.remove('active');
   612→      currentCandidateId = null;
   613→    }
   614→
   615→    function formatStatus(status) {
   616→      const statuses = {
   617→        'pending': 'Pending',
   618→        'in_progress': 'In Progress',
   619→        'completed': 'Completed'
   620→      };
   621→      return statuses[status] || 'Unknown';
   622→    }
   623→
   624→    function formatDate(dateString) {
   625→      if (!dateString) return '—';
   626→      const date = new Date(dateString);
   627→      return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
   628→    }
   629→
   630→    function escapeHtml(text) {
   631→      if (!text) return '';
   632→      const map = {
   633→        '&': '&amp;',
   634→        '<': '&lt;',
   635→        '>': '&gt;',
   636→        '"': '&quot;',
   637→        "'": '&#039;'
   638→      };
   639→      return text.replace(/[&<>"']/g, m => map[m]);
   640→    }
   641→
   642→    function viewDocContent(docId, docType) {
   643→      const doc = (window._currentDocs || []).find(d => d.id === docId);
   644→      if (!doc || !doc.document_content) return;
   645→
   646→      const content = typeof doc.document_content === 'string' ? JSON.parse(doc.document_content) : doc.document_content;
   647→      let bodyHtml = '';
   648→
   649→      if (content.form_type === 'I-9') {
   650→        bodyHtml = `
   651→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Employment Eligibility Verification</p>
   652→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   653→          <p><strong>DOB:</strong> ${content.date_of_birth ? new Date(content.date_of_birth).toLocaleDateString() : ''}</p>
   654→          <p><strong>Address:</strong> ${escapeHtml(content.address || '')}, ${escapeHtml(content.city || '')}, ${escapeHtml(content.state || '')} ${escapeHtml(content.zip || '')}</p>
   655→          <p><strong>SSN:</strong> ${content.ssn_last_four}</p>
   656→          <p><strong>Employer:</strong> ${escapeHtml(content.company || '')}</p>
   657→        `;
   658→      } else if (content.form_type === 'W-4') {
   659→        bodyHtml = `
   660→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">W-4 Tax Withholding</p>
   661→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   662→          <p><strong>Address:</strong> ${escapeHtml(content.city_state_zip || '')}</p>
   663→          <p><strong>Filing Status:</strong> ${escapeHtml(content.filing_status || 'Single')}</p>
   664→        `;
   665→      } else if (content.form_type === 'Direct Deposit Authorization') {
   666→        bodyHtml = `
   667→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Direct Deposit</p>
   668→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   669→          <p><strong>Bank:</strong> ${escapeHtml(content.bank_name || '')}</p>
   670→          <p><strong>Account Type:</strong> ${escapeHtml(content.account_type || '')}</p>
   671→        `;
   672→      } else {
   673→        bodyHtml = `<pre style="white-space: pre-wrap; font-size: 12px;">${JSON.stringify(content, null, 2)}</pre>`;
   674→      }
   675→
   676→      if (doc.signed_at) {
   677→        bodyHtml += `<hr style="margin: 12px 0;"><p style="color: #10b981; font-weight: 600;">✓ Signed on ${new Date(doc.signed_at).toLocaleString()}</p>`;
   678→        if (doc.signer_ip) bodyHtml += `<p style="font-size: 11px; color: #888;">IP: ${escapeHtml(doc.signer_ip)}</p>`;
   679→      }
   680→
   681→      const overlay = document.createElement('div');
   682→      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:2000;display:flex;align-items:center;justify-content:center;';
   683→      overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
   684→      overlay.innerHTML = `
   685→        <div style="background:var(--card-bg);border-radius:12px;max-width:500px;width:90%;padding:24px;max-height:80vh;overflow-y:auto;">
   686→          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
   687→            <h3 style="font-size:16px;font-weight:600;">${escapeHtml(docType)}</h3>
   688→            <button onclick="this.closest('[style*=fixed]').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-muted);">✕</button>
   689→          </div>
   690→          <div style="font-size:13px;line-height:1.7;">${bodyHtml}</div>
   691→        </div>
   692→      `;
   693→      document.body.appendChild(overlay);
   694→    }
   695→
   696→    function downloadAllDocs() {
   697→      const docs = window._currentDocs || [];
   698→      docs.forEach((doc, i) => {
   699→        if (doc.document_content) {
   700→          setTimeout(() => {
   701→            window.open(`/api/onboarding/recruiter/document/${doc.id}/download`, '_blank');
   702→          }, i * 500);
   703→        }
   704→      });
   705→    }
   706→
   707→    // Modal close on click outside
   708→    document.getElementById('modal').addEventListener('click', (e) => {
   709→      if (e.target.id === 'modal') closeModal();
   710→    });
   711→
   712→    // Initialize
   713→    document.addEventListener('DOMContentLoaded', () => {
   714→      loadOnboardingDocuments();
   715→      setupUserMenu();
   716→      // Auto-refresh every 30 seconds for real-time updates
   717→      setInterval(loadOnboardingDocuments, 30000);
   718→    });
   719→  </script>
