   270→    async function loadCompanyProfile() {
   271→      try {
   272→        const data = await apiCall('/company/profile');
   273→        if (!data) return;
   274→
   275→        companyData = data.company;
   276→        populateForm(companyData);
   277→        updateCompleteness(companyData);
   278→        updateVerificationStatus(companyData);
   279→      } catch (err) {
