   303→    function updateCompleteness(company) {
   304→      const fields = [
   305→        company.name,
   306→        company.description,
   307→        company.industry,
   308→        company.company_size,
   309→        company.headquarters,
   310→        company.website,
   311→        company.logo_url,
   312→        company.linkedin_url
   313→      ];
   314→
   315→      const completed = fields.filter(f => f && f.length > 0).length;
   316→      const percentage = Math.round((completed / fields.length) * 100);
   317→
   318→      document.getElementById('completeness-fill').style.width = percentage + '%';
   319→      document.getElementById('completeness-percent').textContent = percentage + '%';
   320→
   321→      if (percentage === 100) {
   322→        document.getElementById('completeness-card').classList.add('complete');
   323→      }
   324→    }
