   326→    function updateVerificationStatus(company) {
   327→      const icon = document.getElementById('verification-icon');
   328→      const title = document.getElementById('verification-title');
   329→      const desc = document.getElementById('verification-desc');
   330→      const btn = document.getElementById('verify-btn');
