   332→
   333→      if (company.is_verified) {
   334→        icon.textContent = '✅';
   335→        title.textContent = 'Verified Company';
   336→        desc.textContent = 'Your company has been verified. Candidates see a verified badge on your jobs.';
   337→        card.classList.add('verified');
   338→      } else if (company.email_domain) {
   339→        icon.textContent = '🔄';
   340→        title.textContent = 'Pending Verification';
   341→        desc.textContent = 'Your work email domain has been registered. Add LinkedIn to complete verification.';
   342→        btn.style.display = company.linkedin_url ? 'none' : 'block';
   343→      } else {
   344→        icon.textContent = '⚠️';
   345→        title.textContent = 'Not Verified';
   346→        desc.textContent = 'Use a company email address to verify your company automatically.';
   347→        btn.style.display = 'block';
   348→      }
   349→    }
