   351→    document.getElementById('profile-form').addEventListener('submit', async (e) => {
   352→      e.preventDefault();
   353→      const form = e.target;
   354→      const submitBtn = form.querySelector('button[type="submit"]');
   355→      const message = document.getElementById('form-message');
   356→
   357→      submitBtn.disabled = true;
   358→      submitBtn.textContent = 'Saving...';
   359→
   360→      try {
   361→        const response = await apiCall('/company/profile', {
   362→          method: 'PUT',
   363→          body: JSON.stringify({
   364→            name: form.name.value,
   365→            description: form.description.value,
   366→            industry: form.industry.value,
   367→            company_size: form.company_size.value,
   368→            headquarters: form.headquarters.value,
   369→            founded_year: form.founded_year.value ? parseInt(form.founded_year.value) : null,
   370→            website: form.website.value,
   371→            linkedin_url: form.linkedin_url.value,
   372→            logo_url: form.logo_url.value
   373→          })
   374→        });
   375→
   376→        if (response.success) {
   377→          message.textContent = response.message || 'Profile updated successfully!';
   378→          message.className = 'form-message success';
   379→          message.style.display = 'block';
   380→
   381→          // Update completeness
   382→          if (response.company) {
   383→            updateCompleteness(response.company);
   384→          }
   385→
   386→          setTimeout(() => {
   387→            message.style.display = 'none';
   388→          }, 3000);
   389→        } else {
   390→          throw new Error(response.error || 'Failed to update profile');
   391→        }
   392→      } catch (err) {
   393→        message.textContent = err.message;
   394→        message.className = 'form-message error';
   395→        message.style.display = 'block';
   396→      } finally {
   397→        submitBtn.disabled = false;
   398→        submitBtn.textContent = 'Save Changes';
   399→      }
   400→    });
