   811→    // Display video practice coaching
   812→    function displayVideoPracticeCoaching() {
   813→      if (!practiceAnalysisData) {
   814→        alert('No analysis data available.');
   815→        return;
   816→      }
   817→
   818→      const scores = practiceAnalysisData.scores;
   819→      const resultContainer = document.getElementById('coaching-result');
   820→
   821→      const insights = [];
   822→
   823→      if (scores.eyeContact >= 70) {
   824→        insights.push('✅ Strong eye contact maintained throughout');
   825→      } else {
   826→        insights.push('💡 Practice looking directly at the camera lens');
   827→      }
   828→
   829→      if (scores.bodyLanguage >= 70) {
   830→        insights.push('✅ Good posture and head stability');
   831→      } else {
   832→        insights.push('💡 Keep your head steady and maintain good posture');
   833→      }
   834→
   835→      if (scores.presentation >= 70) {
   836→        insights.push('✅ Excellent overall video presence');
   837→      } else {
   838→        insights.push('💡 Practice recording yourself to improve presence');
   839→      }
   840→
   841→      resultContainer.innerHTML = `
   842→        <div class="score-display">
   843→          <div class="score-value">${scores.presentation}/100</div>
   844→          <div class="score-label">Presentation Score</div>
   845→        </div>
   846→
   847→        <div class="coaching-section">
   848→          <h4>📊 Video Analysis</h4>
   849→          <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 1rem; margin-top: 1rem;">
   850→            <div style="text-align: center; padding: 1rem; background: white; border-radius: 12px;">
   851→              <div style="font-size: 2rem; font-weight: 700; color: #667eea;">${scores.eyeContact}</div>
   852→              <div style="font-size: 0.875rem; color: #64748b;">Eye Contact</div>
   853→            </div>
   854→            <div style="text-align: center; padding: 1rem; background: white; border-radius: 12px;">
   855→              <div style="font-size: 2rem; font-weight: 700; color: #667eea;">${scores.bodyLanguage}</div>
   856→              <div style="font-size: 0.875rem; color: #64748b;">Body Language</div>
   857→            </div>
   858→            <div style="text-align: center; padding: 1rem; background: white; border-radius: 12px;">
   859→              <div style="font-size: 2rem; font-weight: 700; color: #667eea;">${scores.expression}</div>
   860→              <div style="font-size: 0.875rem; color: #64748b;">Expression</div>
   861→            </div>
   862→          </div>
   863→        </div>
   864→
